<!DOCTYPE html>
<html lang="id">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Dimensi Laptop & Handphone</title>
  <link href="https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@400;500;600;700&family=Inter:wght@400;500;600&display=swap" rel="stylesheet">
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body { font-family: "Plus Jakarta Sans", sans-serif; background: #f0ede8; color: #1a1a1a; }
    .navbar { background: #fff; border-bottom: 0.5px solid #e0dcd6; padding: 0 24px; height: 52px; display: flex; align-items: center; gap: 16px; position: sticky; top: 0; z-index: 100; }
    .search-bar { flex: 1; max-width: 420px; background: #f5f3ef; border: 0.5px solid #e0dcd6; border-radius: 8px; display: flex; align-items: center; gap: 8px; padding: 0 12px; height: 34px; }
    .search-bar input { border: none; background: transparent; font-size: 13px; font-family: inherit; color: #1a1a1a; outline: none; flex: 1; }
    .search-bar input::placeholder { color: #aaa; }
    .nav-links { display: flex; gap: 4px; margin-left: auto; }
    .nav-links a { font-size: 13px; font-weight: 500; color: #555; padding: 6px 12px; border-radius: 6px; cursor: pointer; text-decoration: none; transition: background .15s, color .15s; }
    .nav-links a:hover, .nav-links a.active { background: #f0ede8; color: #1a1a1a; }
    .nav-icons { display: flex; gap: 4px; margin-left: 8px; }
    .nav-icon { width: 34px; height: 34px; display: flex; align-items: center; justify-content: center; border-radius: 8px; cursor: pointer; border: 0.5px solid #e0dcd6; background: #fff; transition: background .15s; position: relative; }
    .nav-icon:hover { background: #f0ede8; }
    .cart-badge { position: absolute; top: -4px; right: -4px; width: 16px; height: 16px; background: #e85d2a; border-radius: 50%; font-size: 10px; color: #fff; display: flex; align-items: center; justify-content: center; font-weight: 700; }
    .hero { background: linear-gradient(135deg, #1a3fa6 0%, #0d2270 60%, #0a1a5c 100%); padding: 36px 32px; display: flex; align-items: center; gap: 24px; position: relative; overflow: hidden; }
    .hero::before { content: ""; position: absolute; right: -60px; top: -60px; width: 320px; height: 320px; border-radius: 50%; background: rgba(255,255,255,0.05); }
    .hero::after { content: ""; position: absolute; right: 80px; bottom: -80px; width: 200px; height: 200px; border-radius: 50%; background: rgba(255,255,255,0.04); }
    .hero-logo { display: flex; align-items: center; gap: 14px; z-index: 1; }
    .hero-logo-icon { width: 64px; height: 64px; background: rgba(255,255,255,0.15); border-radius: 14px; display: flex; align-items: center; justify-content: center; font-family: "Inter", sans-serif; font-size: 24px; font-weight: 700; color: #fff; letter-spacing: -1px; }
    .hero-text { z-index: 1; }
    .hero-title { font-family: "Inter", sans-serif; font-size: 32px; font-weight: 700; color: #fff; letter-spacing: -1.5px; line-height: 1; }
    .hero-sub { font-size: 13px; color: rgba(255,255,255,0.7); margin-top: 4px; font-weight: 500; letter-spacing: .5px; }
    .hero-contact { margin-top: 10px; font-size: 12px; color: rgba(255,255,255,0.55); }
    .hero-contact span { display: inline-block; margin-right: 16px; }
    .main { padding: 24px; }
    .section-header { display: flex; align-items: center; justify-content: space-between; margin-bottom: 16px; }
    .see-all { font-size: 13px; font-weight: 600; color: #e85d2a; cursor: pointer; text-decoration: none; }
    .category-dropdown { position: relative; display: inline-block; margin-bottom: 24px; }
    .category-btn { display: flex; align-items: center; gap: 8px; padding: 12px 20px; background: #f55e18; color: #1a1a1a; border: none; border-radius: 8px; font-size: 14px; font-weight: 600; cursor: pointer; font-family: inherit; }
    .category-btn svg { transition: transform .2s; }
    .category-dropdown.open .category-btn svg { transform: rotate(180deg); }
    .category-menu { position: absolute; top: calc(100% + 6px); left: 0; background: #fff; border: 0.5px solid #e0dcd6; border-radius: 10px; box-shadow: 0 8px 24px rgba(0,0,0,0.12); min-width: 200px; opacity: 0; visibility: hidden; transform: translateY(-8px); transition: all .2s ease; z-index: 50; overflow: hidden; }
    .category-dropdown.open .category-menu { opacity: 1; visibility: visible; transform: translateY(0); }
    .category-item { display: flex; align-items: center; gap: 10px; padding: 12px 16px; font-size: 13px; font-weight: 500; color: #555; cursor: pointer; transition: all .15s; border-bottom: 0.5px solid #f0ede8; }
    .category-item:last-child { border-bottom: none; }
    .category-item:hover { background: #f5f3ef; color: #1a3fa6; }
    .category-item.active { background: #1a3fa6; color: #fff; }
    .category-item svg { width: 18px; height: 18px; opacity: 0.7; }
    .category-item.active svg { opacity: 1; }
    .filter-bar { display: flex; gap: 8px; margin-bottom: 20px; flex-wrap: wrap; justify-content: center; }
    .filter-chip { flex: 1; min-width: 80px; text-align: center; padding: 9px 16px; border-radius: 20px; border: 0.5px solid #d0ccc6; background: #fff; font-size: 12px; font-weight: 600; cursor: pointer; color: #666; transition: all .15s; }
    .filter-chip.active, .filter-chip:hover { background: #f0ede8; border-color: #1a3fa6; color: #1a3fa6; }
    .products-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(190px, 1fr)); gap: 14px; }
    .product-card { background: #fff; border-radius: 14px; border: 0.5px solid #e0dcd6; overflow: hidden; cursor: pointer; transition: transform .18s, box-shadow .18s; position: relative; }
    .product-card:hover { transform: translateY(-3px); box-shadow: 0 8px 24px rgba(0,0,0,0.1); }
    .product-img-placeholder { width: 100%; aspect-ratio: 4/3; background: #f5f3ef; display: flex; align-items: center; justify-content: center; overflow: hidden; }
    .product-img-placeholder img { width: 100%; height: 100%; object-fit: cover; display: block; }
    .img-fallback { flex-direction: column; align-items: center; gap: 6px; color: #bbb; font-size: 11px; display: none; }
    .product-body { padding: 12px 14px 14px; }
    .product-price { font-family: "Inter", sans-serif; font-size: 15px; font-weight: 600; color: #c04a1a; letter-spacing: -0.3px; margin-bottom: 5px; display: flex; align-items: baseline; gap: 3px; }
    .price-currency { font-size: 11px; font-weight: 500; color: #c04a1a; opacity: 0.75; }
    .price-number { font-size: 17px; font-weight: 600; color: #c04a1a; letter-spacing: -0.5px; }
    .product-name { font-size: 11.5px; color: #666; line-height: 1.45; margin-bottom: 9px; min-height: 33px; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; }
    .product-stock { font-size: 11px; font-weight: 600; color: #999; display: flex; align-items: center; gap: 5px; }
    .stock-dot { width: 6px; height: 6px; border-radius: 50%; background: #22c55e; display: inline-block; }
    .stock-dot.low { background: #f59e0b; }
    .stock-dot.out { background: #ef4444; }
    .badge-new { position: absolute; top: 8px; left: 8px; background: #1a3fa6; color: #fff; font-size: 10px; font-weight: 700; padding: 3px 8px; border-radius: 4px; text-transform: uppercase; }
    .badge-hot { position: absolute; top: 8px; left: 8px; background: #e85d2a; color: #fff; font-size: 10px; font-weight: 700; padding: 3px 8px; border-radius: 4px; text-transform: uppercase; }
    .empty-state { padding: 48px; text-align: center; color: #aaa; font-size: 14px; }
    .modal-overlay { display: none; position: fixed; inset: 0; background: rgba(0,0,0,0.5); z-index: 200; align-items: center; justify-content: center; }
    .modal-overlay.open { display: flex; }
    .modal { background: #fff; border-radius: 18px; width: 90%; max-width: 480px; max-height: 85vh; overflow-y: auto; padding: 24px; position: relative; }
    .modal-img { width: 100%; aspect-ratio: 16/10; background: #f5f3ef; border-radius: 10px; overflow: hidden; margin-bottom: 16px; }
    .modal-img img { width: 100%; height: 100%; object-fit: cover; display: block; }
    .modal-price { font-family: "Inter", sans-serif; font-size: 22px; font-weight: 600; color: #c04a1a; margin-bottom: 6px; display: flex; align-items: baseline; gap: 4px; }
    .modal-price-currency { font-size: 13px; font-weight: 500; color: #c04a1a; opacity: 0.7; }
    .modal-price-number { font-size: 24px; font-weight: 600; color: #c04a1a; letter-spacing: -0.8px; }
    .modal-name { font-size: 15px; font-weight: 600; color: #1a1a1a; margin-bottom: 8px; line-height: 1.4; }
    .modal-desc { font-size: 13px; color: #777; line-height: 1.65; margin-bottom: 16px; }
    .modal-meta { display: flex; gap: 10px; margin-bottom: 20px; flex-wrap: wrap; }
    .modal-meta-item { background: #f5f3ef; border-radius: 8px; padding: 8px 14px; font-size: 12px; color: #777; }
    .modal-meta-item strong { display: block; font-size: 13px; color: #1a1a1a; font-weight: 600; margin-bottom: 2px; }
    .btn-primary { width: 100%; background: #1a3fa6; color: #fff; border: none; border-radius: 10px; padding: 13px; font-size: 14px; font-weight: 600; cursor: pointer; font-family: inherit; transition: background .15s; }
    .btn-primary:hover { background: #1433a0; }
    .btn-close { position: absolute; top: 16px; right: 16px; width: 32px; height: 32px; border-radius: 50%; border: 0.5px solid #e0dcd6; background: #fff; cursor: pointer; font-size: 16px; display: flex; align-items: center; justify-content: center; }
    .selected-category { display: inline-flex; align-items: center; gap: 6px; margin-left: 12px; padding: 6px 12px; background: #f0ede8; border-radius: 20px; font-size: 12px; font-weight: 600; color: #1a3fa6; }
    .selected-category .clear-cat { width: 16px; height: 16px; display: flex; align-items: center; justify-content: center; background: #1a3fa6; color: #fff; border-radius: 50%; font-size: 10px; cursor: pointer; margin-left: 4px; }
    .selected-category .clear-cat:hover { background: #e85d2a; }
  </style>
</head>
<body>
  <nav class="navbar">
    <div class="search-bar">
      <svg width="14" height="14" fill="none" stroke="#aaa" stroke-width="2" viewBox="0 0 24 24"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.35-4.35"/></svg>
      <input type="text" id="searchInput" placeholder="Cari produk...">
