    const NO_IMG = `<div class="img-fallback" style="display:flex;flex-direction:column;align-items:center;gap:6px;color:#bbb;font-size:11px;width:100%;height:100%;justify-content:center"><svg width="32" height="32" fill="none" stroke="#ccc" stroke-width="1.5" viewBox="0 0 24 24"><rect x="3" y="3" width="18" height="18" rx="2"/><circle cx="8.5" cy="8.5" r="1.5"/><polyline points="21 15 16 10 5 21"/></svg><span>Gambar tidak tersedia</span></div>`;

    function imgTag(src, alt) {
      if (src && IMGS[src]) {
        return `<img src="${IMGS[src]}" alt="${alt}" style="width:100%;height:100%;object-fit:cover;display:block;">`;
      }
      return NO_IMG;
    }

    const products = [
