      { id:15, name:"Laptop Lenovo ThinkPad T470 Core i5-7300U 8GB 256GB SSD",price:2800000, stock:2, cat:"laptop", filter:"second", badge:null,  img:"lenovo_ideapad", desc:"ThinkPad legendaris kondisi baik. Keyboard nyaman, baterai masih bagus. Cocok untuk kerja." },
      { id:16, name:"Laptop Dell Latitude 5490 Core i7-8650U 16GB 512GB SSD", price:3500000, stock:1, cat:"laptop", filter:"second", badge:null,  img:"dell_lat5490",   desc:"Dell Latitude grade B+. Layar FHD 14 inci, performa kencang untuk multitasking berat." },
      { id:17, name:"Laptop HP EliteBook 840 G5 Core i5-8350U 8GB 256GB SSD",price:2600000, stock:3, cat:"laptop", filter:"second", badge:"hot", img:"hp_elitebook",   desc:"HP EliteBook premium dengan build quality metal. Fingerprint, backlit keyboard. Kondisi sangat baik." },
      { id:18, name:"Laptop ASUS X441B AMD A9-9420 4GB 1TB HDD",              price:1400000, stock:2, cat:"laptop", filter:"second", badge:null,  img:"asus_a516",      desc:"Laptop entry level kondisi cukup baik. Cocok untuk keperluan administrasi dan pelajar." },
