      { id:49, name:"WiFi Card Intel 3165NGW M.2 Dual Band BT4.2",    price:135000, stock:11, cat:"komponen", filter:"sperpat", badge:null, img:null, desc:"WiFi card M.2 2230 dual band." },
      { id:50, name:"Baterai CMOS CR2032 Motherboard Laptop",          price:15000,  stock:50, cat:"komponen", filter:"sperpat", badge:null, img:null, desc:"Baterai CMOS CR2032 untuk laptop dan PC." },
    ];

    const categoryNames = { semua:"Semua Produk", laptop:"Laptop", handphone:"Handphone", monitor:"Monitor", printer:"Printer", komponen:"Komponen", aksesoris:"Aksesoris" };
    let cart=[], activeFilter="semua", activeCat="semua", searchQ="";

    function fmtPrice(n) {
      if(n===0) return `<span class="price-currency" style="opacity:1">Hubungi Kami</span>`;
      return `<span class="price-currency">Rp</span><span class="price-number">${n.toLocaleString("id-ID")}</span>`;
    }
    function fmtPriceModal(n) {
      if(n===0) return `<span class="modal-price-currency" style="opacity:1">Hubungi Kami</span>`;
      return `<span class="modal-price-currency">Rp</span><span class="modal-price-number">${n.toLocaleString("id-ID")}</span>`;
    }
    function stockClass(s){ return s===0?"out":s<=2?"low":""; }
    function stockLabel(s){ return s===0?"Stok Habis":`Stok ${s}`; }

    function render() {
      const filtered = products.filter(p => {
        return (activeCat==="semua"||p.cat===activeCat) &&
               (activeFilter==="semua"||p.filter===activeFilter) &&
               (!searchQ||p.name.toLowerCase().includes(searchQ.toLowerCase()));
      });
      const grid = document.getElementById("productsGrid");
      if(!filtered.length){ grid.innerHTML=`<div class="empty-state">Produk tidak ditemukan &#128269;</div>`; return; }
      grid.innerHTML = filtered.map(p => `
        <div class="product-card" onclick="openModal(${p.id})">
          ${p.badge==="new"?`<div class="badge-new">Baru</div>`:p.badge==="hot"?`<div class="badge-hot">&#128293; Hot</div>`:""}
          <div class="product-img-placeholder">${imgTag(p.img, p.name)}</div>
          <div class="product-body">
            <div class="product-price">${fmtPrice(p.price)}</div>
            <div class="product-name">${p.name}</div>
            <div class="product-stock"><span class="stock-dot ${stockClass(p.stock)}"></span>${stockLabel(p.stock)}</div>
          </div>
        </div>`).join("");
    }

    function openModal(id) {
      const p = products.find(x=>x.id===id);
      document.getElementById("modalContent").innerHTML = `
        <div class="modal-img">${imgTag(p.img, p.name)}</div>
        <div class="modal-price">${fmtPriceModal(p.price)}</div>
        <div class="modal-name">${p.name}</div>
        <div class="modal-desc">${p.desc}</div>
        <div class="modal-meta">
          <div class="modal-meta-item"><strong>${stockLabel(p.stock)}</strong>Stok</div>
          <div class="modal-meta-item"><strong>${p.cat.charAt(0).toUpperCase()+p.cat.slice(1)}</strong>Kategori</div>
          <div class="modal-meta-item"><strong>${p.filter==="baru"?"Baru":p.filter==="second"?"Second":"Sperpat"}</strong>Kondisi</div>
        </div>
        <button class="btn-primary" onclick="addCart(${p.id})">+ Tambah ke Keranjang</button>`;
      document.getElementById("modalOverlay").classList.add("open");
    }

    function addCart(id){ cart.push(id); document.getElementById("cartCount").textContent=cart.length; document.getElementById("modalOverlay").classList.remove("open"); }
    document.getElementById("modalClose").onclick=()=>document.getElementById("modalOverlay").classList.remove("open");
    document.getElementById("modalOverlay").onclick=e=>{if(e.target===e.currentTarget)e.currentTarget.classList.remove("open");};

    const catDD = document.getElementById("categoryDropdown");
    document.getElementById("categoryBtn").onclick=e=>{e.stopPropagation();catDD.classList.toggle("open");};
    document.addEventListener("click",e=>{if(!catDD.contains(e.target))catDD.classList.remove("open");});
    document.querySelectorAll(".category-item").forEach(item=>{
      item.onclick=()=>{
        document.querySelectorAll(".category-item").forEach(x=>x.classList.remove("active"));
        item.classList.add("active"); activeCat=item.dataset.cat; catDD.classList.remove("open");
        const badge=document.getElementById("selectedCategoryBadge");
        badge.innerHTML=activeCat==="semua"?"":
          `<span class="selected-category">${categoryNames[activeCat]}<span class="clear-cat" onclick="clearCat()">&#10005;</span></span>`;
        document.getElementById("sectionTitle").textContent=categoryNames[activeCat]||"Semua Produk";
        render();
      };
    });
    function clearCat(){ activeCat="semua"; document.querySelectorAll(".category-item").forEach(x=>x.classList.toggle("active",x.dataset.cat==="semua")); document.getElementById("selectedCategoryBadge").innerHTML=""; document.getElementById("sectionTitle").textContent="Semua Produk"; render(); }
    document.querySelectorAll(".filter-chip").forEach(t=>{
      t.onclick=()=>{ document.querySelectorAll(".filter-chip").forEach(x=>x.classList.remove("active")); t.classList.add("active"); activeFilter=t.dataset.filter; render(); };
    });
    document.getElementById("searchInput").oninput=e=>{searchQ=e.target.value;render();};
    render();
  </script>
</body>
</html>